123→/// Execute a function with given inputs via the raw protocol.
124→///
125→/// The Rust frontend's Execute command requires a `file` field (unlike TS/Go
126→/// frontends that hold instrumented code in memory). We send a raw JSON request
127→/// to include the file path.
128→async fn execute_function_raw(
129→    frontend: &mut Frontend,
130→    file: &str,
131→    function_name: &str,
132→    inputs: Vec<serde_json::Value>,
133→) -> shatter_core::protocol::ExecuteResult {
134→    // Build raw JSON request with the file field included.
135→    let request_json = serde_json::json!({
136→        "protocol_version": "0.1.0",
137→        "id": 0,  // will be overridden by send_raw
138→        "command": "execute",
139→        "file": file,
140→        "function": function_name,
141→        "inputs": inputs,
142→        "mocks": []
143→    });
144→
145→    let response = frontend
146→        .send_raw(request_json)
147→        .await
148→        .expect("execute command failed");
149→
150→    match response.result {
151→        ResponseResult::Execute(result) => *result,
152→        ResponseResult::Error { code, message, .. } => {
153→            panic!("execute error ({code:?}): {message}");
154→        }
155→        other => panic!("expected Execute response, got: {other:?}"),
156→    }
157→}
158→
159→/// Collect distinct return value strings from a set of execution results.
160→fn collect_return_values(
161→    results: &[shatter_core::protocol::ExecuteResult],
162→) -> HashSet<String> {
163→    results
164→        .iter()
165→        .map(|exec| {
166→            if let Some(ref err) = exec.thrown_error {
167→                format!("ERROR:{}", err.message)
168→            } else {
169→                match &exec.return_value {
170→                    Some(v) => v.to_string(),
171→                    None => "null".to_string(),
172→                }
173→            }
174→        })
175→        .collect()
176→}
