182→/// classify_number — 4 branches: n<0 -> "negative", n==0 -> "zero",
183→/// n<=100 -> "small positive", n>100 -> "large positive".
184→#[tokio::test]
185→async fn rust_explore_classify_number() {
186→    let file = rust_examples_dir().join("arithmetic.rs");
187→    let file_str = file.to_string_lossy().to_string();
188→
189→    let mut frontend = spawn_rust_frontend().await;
190→
191→    // Analyze: verify parameter signature.
192→    let analysis = analyze_function(&mut frontend, &file_str, "classify_number").await;
193→    assert_eq!(analysis.params.len(), 1, "classify_number takes 1 param");
194→    assert_eq!(analysis.params[0].name, "n");
195→
196→    // Verify branches were detected.
197→    assert!(
198→        !analysis.branches.is_empty(),
199→        "should detect branches in classify_number"
200→    );
201→
202→    // Instrument the function.
203→    instrument_function(&mut frontend, &file_str, "classify_number").await;
204→
205→    // Execute with inputs targeting each branch.
206→    let test_inputs: Vec<(serde_json::Value, &str)> = vec![
207→        (serde_json::json!(-5), "\"negative\""),
208→        (serde_json::json!(0), "\"zero\""),
209→        (serde_json::json!(50), "\"small positive\""),
210→        (serde_json::json!(200), "\"large positive\""),
211→    ];
212→
213→    let mut results = Vec::new();
214→    for (input, expected) in &test_inputs {
215→        let result =
216→            execute_function_raw(&mut frontend, &file_str, "classify_number", vec![input.clone()])
217→                .await;
218→
219→        let ret_str = result
220→            .return_value
221→            .as_ref()
222→            .map(|v| v.to_string())
223→            .unwrap_or_else(|| "null".to_string());
224→
225→        assert_eq!(
226→            &ret_str, expected,
227→            "classify_number({input}) should return {expected}, got {ret_str}"
228→        );
229→
230→        results.push(result);
231→    }
232→
233→    // Verify all 4 branches produce distinct execution paths.
234→    let return_values = collect_return_values(&results);
235→    assert_eq!(
236→        return_values.len(),
237→        4,
238→        "should discover all 4 branches; found: {return_values:?}"
239→    );
240→
241→    // Verify branch paths are populated (instrumentation working).
242→    for result in &results {
243→        assert!(
244→            !result.branch_path.is_empty(),
245→            "branch_path should be non-empty for instrumented execution"
246→        );
247→    }
248→
249→    frontend.shutdown().await.expect("frontend shutdown failed");
250→}
